// packages/platform/segments-presets/testing/test-utils.ts
var currentSetup;
var isInitialised = false;
var wrapper = {
  getSegmentsPresets: () => currentSetup.getSegmentsPresets(),
  addRecentSegmentsPreset: (segments) => currentSetup.addRecentSegmentsPreset(segments),
  pinSegmentsPreset: (segments) => currentSetup.pinSegmentsPreset(segments),
  unpinSegmentsPreset: (id) => currentSetup.unpinSegmentsPreset(id)
};
var setupTestingEnv = () => {
  if (typeof expect === "undefined") {
    isInitialised = true;
  }
  mockSegmentsPresets();
};
var mockSegmentsPresets = (setup = {}) => {
  if (!isInitialised) {
    throw new Error(`\`@dynatrace-sdk/segments-presets/testing\` has not been initialised!
Add in your \`jest.config.js\` file entry with \`@dynatrace-sdk/segments-presets/testing\` setup:

\`setupFiles: ['@dynatrace-sdk/segments-presets/testing']\``);
  }
  const globalWithDtRuntimeSegments = globalThis;
  if (globalWithDtRuntimeSegments.dtRuntime === void 0) {
    globalWithDtRuntimeSegments.dtRuntime = {};
  }
  if (globalWithDtRuntimeSegments.dtRuntime.segments === void 0) {
    globalWithDtRuntimeSegments.dtRuntime.segments = wrapper;
  }
  currentSetup = getSetupWithDefaults(setup);
};
var clearSegmentsPresetsMocks = () => {
  mockSegmentsPresets();
};
var getSetupWithDefaults = (setup) => {
  return {
    getSegmentsPresets: async () => setup.getSegmentsPresets?.() || { pinnedPresets: [], recentPresets: [] },
    addRecentSegmentsPreset: async (segments) => setup.addRecentSegmentsPreset?.(segments) || { pinnedPresets: [], recentPresets: [] },
    pinSegmentsPreset: async (segments) => setup.pinSegmentsPreset?.(segments) || { pinnedPresets: [], recentPresets: [] },
    unpinSegmentsPreset: async (id) => setup.unpinSegmentsPreset?.(id) || { pinnedPresets: [], recentPresets: [] }
  };
};

// packages/platform/segments-presets/testing/index.ts
setupTestingEnv();
export {
  clearSegmentsPresetsMocks,
  mockSegmentsPresets,
  setupTestingEnv
};
